"""
Download move / Pokémon metadata from Serebii's Pokémon Champions sections.

Run once (needs internet):

    python scrape_serebii.py

Outputs JSON under ./data/
"""

from __future__ import annotations

import json
import re
import time
from pathlib import Path

import requests
from bs4 import BeautifulSoup

from champions_types import normalize_type_label

HEADERS = {"User-Agent": "PokemonChampionsCalc/1.0 (+local tool)"}

MOVES_URL = "https://www.serebii.net/pokemonchampions/moves.shtml"
STAT_ALL_URL = "https://www.serebii.net/pokedex-champions/stat/all.shtml"
DEX_PREFIX = "https://www.serebii.net"


def _types_from_cell(cell) -> list[str]:
    types: list[str] = []
    for img in cell.find_all("img"):
        alt = (img.get("alt") or "").strip()
        title = (img.get("title") or "").strip()
        for candidate in (alt, title):
            mapped = normalize_type_label(candidate)
            if mapped:
                types.append(mapped)
    # Dedupe preserving order
    seen = set()
    out = []
    for t in types:
        if t not in seen:
            seen.add(t)
            out.append(t)
    return out


def _category_from_cell(cell) -> str | None:
    text = cell.get_text(" ", strip=True).lower()
    if "physical" in text:
        return "Physical"
    if "special" in text:
        return "Special"
    if "status" in text:
        return "Status"
    for img in cell.find_all("img"):
        alt = (img.get("alt") or "").strip().lower()
        if "physical" in alt:
            return "Physical"
        if "special" in alt:
            return "Special"
        if "status" in alt:
            return "Status"
    return None


def _parse_int_maybe(raw: str) -> int | None:
    raw = raw.strip()
    if raw in {"", "--", "—"}:
        return None
    try:
        return int(raw)
    except ValueError:
        return None


def fetch_moves(session: requests.Session) -> list[dict]:
    r = session.get(MOVES_URL, headers=HEADERS, timeout=60)
    r.raise_for_status()
    soup = BeautifulSoup(r.text, "html.parser")

    moves: list[dict] = []
    for row in soup.find_all("tr"):
        link = row.find("a", href=re.compile(r"/attackdex-champions/"))
        if not link:
            continue
        href = link.get("href", "")
        slug_match = re.search(r"/attackdex-champions/([^/]+)\.shtml", href)
        slug = slug_match.group(1) if slug_match else None
        name = link.get_text(strip=True)
        cells = row.find_all("td")
        if len(cells) < 5:
            continue

        type_cell = cells[1]
        cat_cell = cells[2]
        pp = _parse_int_maybe(cells[3].get_text(strip=True))
        power = _parse_int_maybe(cells[4].get_text(strip=True))
        acc = _parse_int_maybe(cells[5].get_text(strip=True)) if len(cells) > 5 else None

        type_names = _types_from_cell(type_cell)
        category = _category_from_cell(cat_cell)

        moves.append(
            {
                "slug": slug,
                "name": name,
                "types": type_names,
                "type": type_names[0] if type_names else None,
                "category": category,
                "pp": pp,
                "base_power": power,
                "accuracy": acc,
                "url": href if href.startswith("http") else DEX_PREFIX + href,
            }
        )

    # Dedupe by slug
    by_slug: dict[str, dict] = {}
    for m in moves:
        key = m.get("slug") or m["name"].lower()
        by_slug[key] = m
    return sorted(by_slug.values(), key=lambda x: x["name"].lower())


def fetch_stat_table(session: requests.Session) -> list[dict]:
    r = session.get(STAT_ALL_URL, headers=HEADERS, timeout=60)
    r.raise_for_status()
    soup = BeautifulSoup(r.text, "html.parser")

    mons: list[dict] = []
    for row in soup.find_all("tr"):
        link = row.find("a", href=re.compile(r"/pokedex-champions/([^/]+)/?"))
        if not link:
            continue
        href = link["href"]
        mslug = re.search(r"/pokedex-champions/([^/]+)/?", href)
        slug = mslug.group(1) if mslug else None
        if not slug or slug == "":
            continue

        name = link.get_text(strip=True)

        tds = row.find_all("td")
        nums = []
        for td in tds:
            txt = td.get_text(strip=True)
            if re.fullmatch(r"\d+", txt):
                nums.append(int(txt))

        if len(nums) < 7:
            continue

        hp, atk, de, spa, spd, spe, total = nums[:7]
        dex_cell = tds[0].get_text(strip=True)
        nat_match = re.search(r"#?(\d+)", dex_cell)
        national = int(nat_match.group(1)) if nat_match else None

        mons.append(
            {
                "slug": slug,
                "name": name,
                "national": national,
                "base_hp": hp,
                "base_attack": atk,
                "base_defense": de,
                "base_spatk": spa,
                "base_spdef": spd,
                "base_speed": spe,
                "base_total": total,
            }
        )

    dedup: dict[tuple[str, str], dict] = {}
    for m in mons:
        dedup[(m["slug"], m["name"])] = m
    return sorted(dedup.values(), key=lambda x: (-x["base_total"], x["name"]))


def fetch_mon_types(session: requests.Session, slug: str) -> tuple[str, ...]:
    url = f"{DEX_PREFIX}/pokedex-champions/{slug}/"
    r = session.get(url, headers=HEADERS, timeout=60)
    r.raise_for_status()
    soup = BeautifulSoup(r.text, "html.parser")

    types: list[str] = []

    def harvest(container):
        for img in container.find_all("img"):
            src = (img.get("src") or "").lower()
            if "/types/" not in src and "/ptype/" not in src:
                continue
            for candidate in ((img.get("alt") or "").strip(), (img.get("title") or "").strip()):
                mapped = normalize_type_label(candidate)
                if mapped:
                    types.append(mapped)

    # Primary layout: section headers include Type near icons
    for td in soup.find_all("td"):
        txt = td.get_text(" ", strip=True)
        if txt == "Type":
            row = td.find_parent("tr")
            if row:
                for cell in row.find_all("td")[1:]:
                    harvest(cell)

    if not types:
        for div in soup.select(".typeicon, .types"):
            harvest(div)

    seen = set()
    ordered: list[str] = []
    for t in types:
        if t not in seen:
            seen.add(t)
            ordered.append(t)
    return tuple(ordered)


def enrich_pokemon(session: requests.Session, mons: list[dict], pause: float = 0.2) -> None:
    for i, m in enumerate(mons):
        slug = m["slug"]
        try:
            m["types"] = list(fetch_mon_types(session, slug))
        except Exception as exc:  # noqa: BLE001
            m["types"] = []
            m["types_error"] = str(exc)
        if pause:
            time.sleep(pause)
        if (i + 1) % 25 == 0:
            print(f"  typed {i + 1}/{len(mons)} Pokémon")


def main() -> None:
    out_dir = Path(__file__).resolve().parent / "data"
    out_dir.mkdir(exist_ok=True)

    session = requests.Session()
    print("Fetching moves …")
    moves = fetch_moves(session)
    (out_dir / "moves.json").write_text(json.dumps(moves, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"  wrote {len(moves)} moves -> data/moves.json")

    print("Fetching Pokémon base stats …")
    mons = fetch_stat_table(session)
    (out_dir / "pokemon_stats.json").write_text(
        json.dumps(mons, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    print(f"  wrote {len(mons)} stat rows -> data/pokemon_stats.json")

    print("Fetching Pokémon types (this takes a few minutes) …")
    enrich_pokemon(session, mons)
    (out_dir / "pokemon.json").write_text(json.dumps(mons, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"  wrote data/pokemon.json")


if __name__ == "__main__":
    main()

